    @Test
    fun `Given a multiline if-expression with else-if and elvis operator then do not rewrite else-if into nested if`() {
        val code =
            """
            fun foo(showFilter: Boolean, activeTabIndex: State<Int>) {
                val x = if (showFilter) {
                    1
                } else if (activeTabIndex.value == 0) {
                    2
                } else {
                    null
                } ?: 0
                println(x)
            }

            interface State<T> {
                val value: T
            }
            """.trimIndent()
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a multiline if-expression with else-if and a chained call then do not rewrite else-if into nested if`() {
        val code =
            """
            fun foo(bar1: Boolean, bar2: Boolean) {
                val foo = if (bar1) {
                    "bar1"
                } else if (bar2) {
                    "bar2"
                } else {
                    "bar3"
                }.plus("foo")
                println(foo)
            }
            """.trimIndent()
        multiLineIfElseRuleAssertThat(code).hasNoLintViolations()
    }
}
